1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // === Base premiums per item type ===
15	  it("single sword → base premium 100 G + first insurance 10 G + fee 5 G = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 115 });
21	  });
22	  it("single amulet → 60 G base + 6 G first insurance + 5 G fee = 71 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 71 });
28	  });
29	  it("single staff → 80 + 8 + 5 = 93 G", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result.results[0]).toEqual({ premium: 93 });
35	  });
36	  it("single potion → 40 + 4 + 5 = 49 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result.results[0]).toEqual({ premium: 49 });
42	  });
43	
44	  // === Components (runes/moonstones) ===
45	  it("2 runes → 50 G base + 5 G first insurance + 5 G fee = 60 G", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [
49	        { op: "quote", items: [{ type: "rune" }, { type: "rune" }] },
50	      ],
51	    });
52	    expect(result.results[0]).toEqual({ premium: 60 });
53	  });
54	  it("3 runes → 60 G base (block) + 6 + 5 = 71 G", () => {
55	    const result = runScenario({
56	      customer: { yearsWithMHPCO: 0 },
57	      steps: [
58	        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
59	      ],
60	    });
61	    expect(result.results[0]).toEqual({ premium: 71 });
62	  });
63	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
64	  it.todo("7 runes → 175 G base premium (3 in a block + 4 individuals)");
65	
66	  // === Alike components clarification ===
67	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
68	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
69	
70	  // === Item-specific modifiers ===
71	  it.todo("cursed sword adds 50% of sword base premium as surcharge");
72	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge");
73	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
74	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
75	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
76	
77	  // === Policy-wide modifiers ===
78	  it.todo("customer with ≥ 2 years (loyalty) receives 20% discount on policy base premium");
79	  it.todo("customer with exactly 2 years → loyalty discount applies");
80	  it.todo("first insurance carries 10% initial assessment surcharge per item");
81	  it.todo("each contract after the first gets 15% follow-up discount");
82	
83	  // === Multi-item modifier scope ===
84	  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee");
85	
86	  // === Rounding ===
87	  it.todo("premium yielding 197.5 G → rounded up to 198 G (in MHPCO's favor)");
88	  it.todo("payout yielding 350.5 G → rounded down to 350 G (in MHPCO's favor)");
89	
90	  // === Integration examples ===
91	  it.todo("newcomer (0 years, no prior) with cursed sword enchantment 3 → premium 165 G");
92	  it.todo("long-standing customer (3 years) second quote, cursed sword enchantment 7 → premium 160 G");
93	
94	  // === Claim — standard reimbursement ===
95	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
96	  it.todo("rune damage 200 G → payout 100 G");
97	
98	  // === Claim — high enchantment clause ===
99	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
100	  it.todo("dragon-material sword enchantment 8, damage 1000 G → payout 400 G (high-enchantment wins)");
101	
102	  // === Claim — dragon material clause ===
103	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
104	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
105	
106	  // === Deductible per damage event ===
107	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
108	
109	  // === Multiple items of same type ===
110	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
111	  it.todo("two sword damages with both swords insured → each treated separately with own deductible");
112	  it.todo("more damage entries than insured items of that type → CLI rejects claim");
113	
114	  // === Cap exhaustion ===
115	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
116	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
117	  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
118	  it.todo("sword cap 2000 G, two successive 1500 G claims → first payout 1400 G, second 600 G");
119	
120	  // === Error handling ===
121	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
122	  it.todo("claim references damage for item not in policy → CLI exits non-zero");
123	  it.todo("claim with negative damage amount → CLI exits non-zero");
124	});
