1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export type StepResult =
41	  | { premium: number }
42	  | { payout: number; remainingCap: number };
43	
44	export interface ScenarioResult {
45	  results: StepResult[];
46	}
47	
48	const PROCESSING_FEE = 5;
49	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
50	
51	const BASE_PREMIUMS: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	};
58	
59	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
60	
61	const sumBasePremiums = (items: Item[]): number => {
62	  const runeCount = items.filter((i) => i.type === "rune").length;
63	  const nonRunes = items.filter((i) => i.type !== "rune");
64	  const runeTotal = runeCount === 3 ? 60 : runeCount * 25;
65	  return runeTotal + nonRunes.reduce((sum, item) => sum + basePremiumFor(item), 0);
66	};
67	
68	const quotePremium = (items: Item[]): number => {
69	  const base = sumBasePremiums(items);
70	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
71	  return base + firstInsuranceSurcharge + PROCESSING_FEE;
72	};
73	
74	const claimPayout = (_step: ClaimStep): StepResult => ({
75	  payout: 0,
76	  remainingCap: 0,
77	});
78	
79	const runStep = (step: Step): StepResult =>
80	  step.op === "quote"
81	    ? { premium: quotePremium(step.items) }
82	    : claimPayout(step);
83	
84	export const runScenario = (scenario: Scenario): ScenarioResult => ({
85	  results: scenario.steps.map(runStep),
86	});
